import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"邀请中心","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"rewards/referral-center.md","filePath":"zh-CN/rewards/referral-center.md"}'),o={name:"rewards/referral-center.md"};function h(l,t,n,i,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="邀请中心" tabindex="-1">邀请中心 <a class="header-anchor" href="#邀请中心" aria-label="Permalink to &quot;邀请中心&quot;">​</a></h1><p>邀请中心用于查看邀请进展、追踪被邀请人状态，以及管理账户的邀请关系绑定。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>「我的」→「邀请中心」</p><h2 id="我的邀请码" tabindex="-1">我的邀请码 <a class="header-anchor" href="#我的邀请码" aria-label="Permalink to &quot;我的邀请码&quot;">​</a></h2><p>页面展示个人专属邀请码，点击可复制分享给好友。好友通过邀请码注册并完成相应操作后，双方可获得活动奖励。</p><h2 id="被邀请人列表" tabindex="-1">被邀请人列表 <a class="header-anchor" href="#被邀请人列表" aria-label="Permalink to &quot;被邀请人列表&quot;">​</a></h2><p>展示通过本账户邀请注册的所有用户，每条记录包含：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>用户信息</td><td>被邀请人昵称（脱敏显示）</td></tr><tr><td>联系方式</td><td>注册手机号（部分隐藏）</td></tr><tr><td>进度状态</td><td>注册 → 开户 → 资产达标，每步附完成日期</td></tr></tbody></table><blockquote><p>资产达标状态每日 20:00 更新。</p></blockquote><h2 id="累计奖励" tabindex="-1">累计奖励 <a class="header-anchor" href="#累计奖励" aria-label="Permalink to &quot;累计奖励&quot;">​</a></h2><p>页面顶部显示通过邀请活动累计获得的奖励金额，支持切换查看不同货币的奖励统计。点击「奖励明细」查看每笔奖励的详细记录。</p><h2 id="搜索" tabindex="-1">搜索 <a class="header-anchor" href="#搜索" aria-label="Permalink to &quot;搜索&quot;">​</a></h2><p>支持按昵称搜索被邀请人，快速查找特定好友的邀请进度。</p><h2 id="修改邀请关系" tabindex="-1">修改邀请关系 <a class="header-anchor" href="#修改邀请关系" aria-label="Permalink to &quot;修改邀请关系&quot;">​</a></h2><p>进入「绑定或修改邀请关系」页面管理账户的邀请绑定状态。</p><p>邀请关系分为三个阶段：</p><table tabindex="0"><thead><tr><th>邀请关系</th><th>说明</th><th>是否可修改</th></tr></thead><tbody><tr><td>注册邀请人</td><td>注册时绑定的邀请人</td><td>注册后不可修改</td></tr><tr><td>开户邀请人</td><td>开户时绑定的邀请人</td><td>开户完成后不可修改</td></tr><tr><td>入资邀请人</td><td>首次入资时绑定的邀请人</td><td>入资前可主动搜索绑定；入资后锁定</td></tr></tbody></table><p>未绑定入资邀请人时，可在该页面主动搜索长桥用户并绑定。</p>',19)])])}const u=a(o,[["render",h]]);export{b as __pageData,u as default};
